impl GitRuntime {
    pub async fn ensure_available(&self) -> Result<()> {
        // 1. 先检查 Aleph 自带的 Git（仅 Windows）
        if self.is_installed() {
            return Ok(());
        }

        // 2. 检查系统 PATH 中的 Git
        if Self::system_git_available() {
            return Ok(());
        }

        // 3. Windows: 自动安装 Portable Git
        #[cfg(windows)]
        {
            self.install().await?;
            return Ok(());
        }

        // 4. macOS/Linux: 返回错误，由上层提示用户安装
        #[cfg(not(windows))]
        {
            return Err(AlephError::runtime(
                "git",
                Self::get_install_hint(),
            ));
        }
    }

    fn system_git_available() -> bool {
        Command::new("git").arg("--version").output()
            .map(|o| o.status.success())
            .unwrap_or(false)
    }

    fn get_install_hint() -> String {
        #[cfg(target_os = "macos")]
        return "Git not found. Install via: xcode-select --install\n  or: brew install git".into();

        #[cfg(target_os = "linux")]
        return "Git not found. Install via: apt install git\n  or: dnf install git".into();

        #[cfg(windows)]
        return "Git not found.".into();
    }
}
