        assert!(result.is_allowed());
    }

    #[test]
    fn test_anonymous_always_denied() {
        let engine = PolicyEngine::new();
        let result = engine.check_tool_permission(&Role::Anonymous, None, "translate");
        assert!(!result.is_allowed());
    }

    #[test]
    fn test_guest_with_scope_allowed() {
