//! mDNS Scanner for discovering Aleph instances
//!
//! Uses mDNS/Zeroconf to discover `_aleph._tcp.local.` services on the local network.

use aleph_protocol::DiscoveredInstance;
use mdns_sd::{ServiceDaemon, ServiceEvent};
use std::time::Duration;
use tracing::{debug, error};

/// mDNS scanner for discovering Aleph instances on the local network
///
/// # Example
///
/// ```no_run
/// use aleph_sdk::discovery::MdnsScanner;
/// use std::time::Duration;
///
/// # async fn example() -> Result<(), String> {
/// let scanner = MdnsScanner::new()?;
/// let instances = scanner.scan(Duration::from_secs(3)).await;
/// println!("Found {} instances", instances.len());
/// # Ok(())
/// # }
/// ```
pub struct MdnsScanner {
    daemon: ServiceDaemon,
}

impl MdnsScanner {
    /// Create a new mDNS scanner
    ///
    /// # Errors
    ///
    /// Returns an error if the mDNS daemon cannot be created (e.g., platform not supported).
    pub fn new() -> Result<Self, String> {
        let daemon = ServiceDaemon::new()
            .map_err(|e| format!("Failed to create mDNS daemon: {}", e))?;
        Ok(Self { daemon })
    }

    /// Scan for Aleph instances on the local network
    ///
    /// # Arguments
    ///
    /// * `timeout` - How long to wait for service discovery responses
    ///
    /// # Returns
    ///
    /// A list of discovered Aleph instances. Returns empty vec if no instances found.
    ///
    /// # Example
    ///
    /// ```no_run
    /// use aleph_sdk::discovery::MdnsScanner;
    /// use std::time::Duration;
    ///
    /// # async fn example() -> Result<(), String> {
    /// let scanner = MdnsScanner::new()?;
    /// let instances = scanner.scan(Duration::from_secs(5)).await;
    /// for instance in instances {
    ///     println!("Found: {} at {}:{}", instance.name, instance.hostname, instance.port);
    /// }
    /// # Ok(())
    /// # }
    /// ```
    pub async fn scan(&self, timeout: Duration) -> Vec<DiscoveredInstance> {
        let service_type = "_aleph._tcp.local.";
        let receiver = match self.daemon.browse(service_type) {
            Ok(rx) => rx,
            Err(e) => {
                error!("Failed to browse mDNS services: {}", e);
                return vec![];
            }
        };

        let mut instances = Vec::new();
        let start = std::time::Instant::now();

        while start.elapsed() < timeout {
            match receiver.try_recv() {
                Ok(ServiceEvent::ServiceResolved(info)) => {
                    debug!("Discovered Aleph instance: {}", info.get_fullname());
                    instances.push(DiscoveredInstance {
                        name: info.get_fullname().to_string(),
                        hostname: info.get_hostname().to_string(),
                        port: info.get_port(),
                        addresses: info
                            .get_addresses()
                            .iter()
                            .map(|addr| addr.to_string())
                            .collect(),
                    });
                }
                Err(std::sync::mpsc::TryRecvError::Empty) => {
                    // No messages yet, sleep briefly
                    tokio::time::sleep(Duration::from_millis(100)).await;
                }
                Err(std::sync::mpsc::TryRecvError::Disconnected) => {
                    // Channel closed, stop scanning
                    break;
                }
                _ => {
                    // Other events (ServiceFound, ServiceRemoved) - ignore
                }
            }
        }

        instances
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_scanner_creation() {
        // Note: This test may fail in CI environments without mDNS support
        match MdnsScanner::new() {
            Ok(_) => {
                println!("mDNS scanner created successfully");
            }
            Err(e) => {
                println!("mDNS not supported in this environment: {}", e);
            }
        }
    }

    #[tokio::test]
    async fn test_scan_returns_vec() {
        match MdnsScanner::new() {
            Ok(scanner) => {
                let instances = scanner.scan(Duration::from_millis(100)).await;
                // Should return a vec (may be empty)
                assert!(instances.is_empty() || !instances.is_empty());
            }
            Err(e) => {
                println!("mDNS not supported in this environment: {}", e);
            }
        }
    }
}
EOF

