//! Guest management commands
//!
//! Provides CLI interface for creating and managing guest invitations.

use clap::Subcommand;
use colored::*;
use serde::{Deserialize, Serialize};

use crate::client::AlephClient;
use crate::error::CliResult;
use aleph_protocol::{CreateInvitationRequest, GuestScope, Invitation};

#[derive(Subcommand)]
pub enum GuestsAction {
    /// Create a new guest invitation
    ///
    /// Examples:
    ///   aleph guests invite --name "Mom" --tools translate,summarize
    ///   aleph guests invite --name "Guest" --tools "*" --ttl 1h
    ///   aleph guests invite --name "Collaborator" --tools "memory:*,search:*"
    Invite {
        /// Guest display name
        #[arg(short, long)]
        name: String,

        /// Allowed tools (comma-separated)
        ///
        /// Examples:
        ///   --tools translate,summarize
        ///   --tools "shell:*"  (all shell tools)
        ///   --tools "*"        (all tools)
        #[arg(short, long)]
        tools: String,

        /// Session expiry after activation (e.g., 7d, 30d)
        ///
        /// This sets the expiry for the activated guest session.
        #[arg(long)]
        session_ttl: Option<String>,

        /// Output format (text or json)
        #[arg(short, long, default_value = "text")]
        format: OutputFormat,
    },

    /// List pending (non-activated) invitations
    List {
        /// Output format (text or json)
        #[arg(short, long, default_value = "text")]
        format: OutputFormat,
    },
}

#[derive(Debug, Clone, Copy)]
pub enum OutputFormat {
    Text,
    Json,
}

impl std::str::FromStr for OutputFormat {
    type Err = String;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        match s.to_lowercase().as_str() {
            "text" => Ok(Self::Text),
            "json" => Ok(Self::Json),
            _ => Err(format!("Invalid format: {}. Use 'text' or 'json'", s)),
        }
    }
}

/// Response for guests.listPending
#[derive(Debug, Clone, Deserialize)]
struct ListPendingResponse {
    invitations: Vec<Invitation>,
}

pub async fn handle_guests(action: GuestsAction, client: &AlephClient) -> CliResult<()> {
    match action {
        GuestsAction::Invite {
            name,
            tools,
            session_ttl,
            format,
        } => handle_invite(client, name, tools, session_ttl, format).await,

        GuestsAction::List { format } => handle_list(client, format).await,
    }
}

async fn handle_invite(
    client: &AlephClient,
    name: String,
    tools: String,
    session_ttl: Option<String>,
    format: OutputFormat,
) -> CliResult<()> {
    // Parse tools list
    let allowed_tools: Vec<String> = tools
        .split(',')
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
        .collect();

    if allowed_tools.is_empty() {
        return Err("At least one tool must be specified".into());
    }

    // Parse session TTL
    let expires_at = if let Some(ttl_str) = session_ttl {
        Some(parse_ttl(&ttl_str)?)
    } else {
        None
    };

    // Create request
    let request = CreateInvitationRequest {
        guest_name: name.clone(),
        scope: GuestScope {
            allowed_tools,
            expires_at,
            display_name: Some(name.clone()),
        },
    };

    // Call Gateway RPC
    let response: Invitation = client
        .call_rpc("guests.createInvitation", Some(serde_json::to_value(&request)?))
        .await?;

    // Display result
    match format {
        OutputFormat::Text => {
            println!("{}", "✓ Invitation created successfully!".green().bold());
            println!();
            println!("  {} {}", "Guest ID:".bold(), response.guest_id);
            println!("  {} {}", "Token:".bold(), response.token);
            println!(
                "  {} {}",
                "Expires at:".bold(),
                format_timestamp(response.expires_at)
            );
            println!();
            println!(
                "  {} {}",
                "Activation URL:".bold(),
                response.url.cyan().underline()
            );
            println!();

            if let Some(exp) = expires_at {
                println!(
                    "  {} {}",
                    "Session expires:".bold(),
                    format_timestamp(exp)
                );
            } else {
                println!("  {} {}", "Session expires:".bold(), "Never".yellow());
            }
        }
        OutputFormat::Json => {
            println!("{}", serde_json::to_string_pretty(&response)?);
        }
    }

    Ok(())
}

async fn handle_list(client: &AlephClient, format: OutputFormat) -> CliResult<()> {
    let response: ListPendingResponse = client.call_rpc("guests.listPending", None).await?;

    match format {
        OutputFormat::Text => {
            if response.invitations.is_empty() {
                println!("{}", "No pending invitations.".yellow());
                return Ok(());
            }

            println!(
                "{}",
                format!("Found {} pending invitation(s):", response.invitations.len()).bold()
            );
            println!();

            for (i, inv) in response.invitations.iter().enumerate() {
                println!(
                    "{}. {} ({})",
                    i + 1,
                    inv.guest_id.cyan(),
                    inv.token.dimmed()
                );
                println!("   Expires: {}", format_timestamp(inv.expires_at));
                println!("   URL: {}", inv.url.underline());
                println!();
            }
        }
        OutputFormat::Json => {
            println!("{}", serde_json::to_string_pretty(&response)?);
        }
    }

    Ok(())
}

/// Parse TTL string (e.g., "1h", "7d", "30d")
fn parse_ttl(ttl_str: &str) -> CliResult<i64> {
    let ttl_str = ttl_str.trim().to_lowercase();
    let (num_str, unit) = if ttl_str.ends_with('d') {
        (&ttl_str[..ttl_str.len() - 1], "days")
    } else if ttl_str.ends_with('h') {
        (&ttl_str[..ttl_str.len() - 1], "hours")
    } else if ttl_str.ends_with('m') {
        (&ttl_str[..ttl_str.len() - 1], "minutes")
    } else {
        return Err(format!("Invalid TTL format: {}. Use 1h, 7d, etc.", ttl_str).into());
    };

    let num: i64 = num_str
        .parse()
        .map_err(|_| format!("Invalid number in TTL: {}", num_str))?;

    let seconds = match unit {
        "days" => num * 86400,
        "hours" => num * 3600,
        "minutes" => num * 60,
        _ => unreachable!(),
    };

    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs() as i64;

    Ok(now + seconds)
}

/// Format Unix timestamp
fn format_timestamp(ts: i64) -> String {
    use chrono::{DateTime, TimeZone, Utc};
    let dt: DateTime<Utc> = Utc.timestamp_opt(ts, 0).unwrap();
    dt.format("%Y-%m-%d %H:%M:%S UTC").to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_ttl_days() {
        let result = parse_ttl("7d").unwrap();
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs() as i64;
        assert!(result > now);
        assert!(result <= now + 7 * 86400 + 1);
    }

    #[test]
    fn test_parse_ttl_hours() {
        let result = parse_ttl("24h").unwrap();
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs() as i64;
        assert!(result > now);
        assert!(result <= now + 24 * 3600 + 1);
    }

    #[test]
    fn test_parse_ttl_minutes() {
        let result = parse_ttl("30m").unwrap();
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs() as i64;
        assert!(result > now);
        assert!(result <= now + 30 * 60 + 1);
    }

    #[test]
    fn test_parse_ttl_invalid_format() {
        assert!(parse_ttl("7").is_err());
        assert!(parse_ttl("abc").is_err());
        assert!(parse_ttl("7x").is_err());
    }

    #[test]
    fn test_parse_ttl_invalid_number() {
        assert!(parse_ttl("abcd").is_err());
        assert!(parse_ttl("d").is_err());
    }

    #[test]
    fn test_output_format_from_str() {
        assert!(matches!(
            "text".parse::<OutputFormat>().unwrap(),
            OutputFormat::Text
        ));
        assert!(matches!(
            "json".parse::<OutputFormat>().unwrap(),
            OutputFormat::Json
        ));
        assert!(matches!(
            "TEXT".parse::<OutputFormat>().unwrap(),
            OutputFormat::Text
        ));
        assert!("invalid".parse::<OutputFormat>().is_err());
    }
}

