    }

    // MARK: - Actions
    private func loadInvitations() {
        guard let core = core else { return }

        Task {
            await MainActor.run { isLoading = true }

            do {
                let client = core.gatewayClient
                let result = try await client.guestsListPending()

                await MainActor.run {
                    invitations = result
                    isLoading = false
                }
