                    if invitation.isExpired {
                        Text("Expired")
                            .font(DesignTokens.Typography.caption)
                            .foregroundColor(.red)
                    } else if let remaining = invitation.timeRemaining {
                        Text("Expires in \(formatTimeRemaining(remaining))")
                            .font(DesignTokens.Typography.caption)
                            .foregroundColor(DesignTokens.Colors.textSecondary)
                    } else {
                        Text("Never expires")
                            .font(DesignTokens.Typography.caption)
                            .foregroundColor(DesignTokens.Colors.textSecondary)
                    }
