import Foundation

// MARK: - Topic Event

/// Generic topic-based event from Gateway
struct TopicEvent: Codable {
    let topic: String
    let data: AnyCodable
    let timestamp: UInt64?
}

/// Type-erased Codable wrapper for event data
struct AnyCodable: Codable {
    let value: Any

    init(_ value: Any) {
        self.value = value
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()

        if let dict = try? container.decode([String: Any].self) {
            value = dict
        } else if let array = try? container.decode([Any].self) {
            value = array
        } else if let string = try? container.decode(String.self) {
            value = string
        } else if let int = try? container.decode(Int.self) {
            value = int
        } else if let double = try? container.decode(Double.self) {
            value = double
        } else if let bool = try? container.decode(Bool.self) {
            value = bool
        } else {
            value = NSNull()
        }
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()

        switch value {
        case let dict as [String: Any]:
            try container.encode(dict)
        case let array as [Any]:
            try container.encode(array)
        case let string as String:
            try container.encode(string)
        case let int as Int:
            try container.encode(int)
        case let double as Double:
            try container.encode(double)
        case let bool as Bool:
            try container.encode(bool)
        default:
            try container.encodeNil()
        }
    }
}

// MARK: - Guest Events

/// Guest-related event types
enum GuestEvent {
    case invitationCreated(GWInvitation)
    case invitationRevoked(String) // token

    /// Parse a TopicEvent into a GuestEvent
    static func parse(from topicEvent: TopicEvent) -> GuestEvent? {
        switch topicEvent.topic {
        case "guest.invitation.created":
            guard let data = topicEvent.data.value as? [String: Any],
                  let invitationData = data["invitation"] as? [String: Any],
                  let jsonData = try? JSONSerialization.data(withJSONObject: invitationData),
                  let invitation = try? JSONDecoder().decode(GWInvitation.self, from: jsonData) else {
                return nil
            }
            return .invitationCreated(invitation)

        case "guest.invitation.revoked":
            guard let data = topicEvent.data.value as? [String: Any],
                  let token = data["token"] as? String else {
                return nil
            }
            return .invitationRevoked(token)

        default:
            return nil
        }
    }
}

